    @Test
    @DisplayName("charset(null) throws IllegalArgumentException when charset argument is null")
    public void test_TC01() {
        // GIVEN a new shell document
        Document doc = Document.createShell("http://example.com");
        // WHEN & THEN: passing null should cause IllegalArgumentException
        assertThrows(IllegalArgumentException.class, () -> doc.charset(null));
        // AND updateMetaCharsetElement remains false
        assertFalse(doc.updateMetaCharsetElement());
        // AND no meta[charset] element is added to head
        assertTrue(doc.head().select("meta[charset]").isEmpty());
    }

