    @DisplayName("charset when syntax is html and no existing meta[charset] appends new meta charset element")
    public void test_TC02() {
        // GIVEN a new shell document with HTML syntax and no existing meta[charset]
        Document doc = Document.createShell("base");
        doc.updateMetaCharsetElement(true);
        doc.outputSettings().syntax(Document.OutputSettings.Syntax.html); // html path
        // WHEN setting charset to UTF-16
        doc.charset(Charset.forName("UTF-16"));
        // THEN a new meta[charset] element is appended with correct charset attribute
        Element meta = doc.head().selectFirst("meta[charset]");
        assertNotNull(meta);
        assertEquals(Charset.forName("UTF-16").displayName(), meta.attr("charset"));
        // AND no obsolete meta[name=charset] elements remain
        assertTrue(doc.head().select("meta[name=charset]").isEmpty());
    }

