        // WHEN setting charset to ISO-8859-1
        doc.charset(Charset.forName("ISO-8859-1"));
        // THEN the existing meta[charset] element is updated to new charset
        Element meta = doc.head().selectFirst("meta[charset]");
        assertNotNull(meta);
        assertEquals(Charset.forName("ISO-8859-1").displayName(), meta.attr("charset"));
    }

